# Terraform: AppStream フリートの切断タイムアウトを 5 分以下に設定します
resource "aws_appstream_fleet" "<example_resource_name>" {
  name          = "<example_resource_name>"
  instance_type = "stream.standard.medium"
  image_name    = "<example_image_name>"

  compute_capacity {
    desired_instances = 1
  }

  disconnect_timeout_in_seconds = 300  # 重要：タイムアウトが <= 300 秒であることを保証します
}
```
